mapper.select:
select DepartMentID
from Bas_DepartMent
where DepartMentName = #{departmentName}

SELECT count(PersonnelCode)
from Bas_Personnel
where PersonnelName = #{personnelName}
  and Mobilephone = #{mobilePhone}
  and AllowUsed = 0

SELECT count(PersonnelCode)
from Bas_Personnel
where PersonnelName = #{personnelName}
  and Mobilephone = #{mobilePhone}
  and AllowUsed = 1

mapper.update:
update Bas_Personnel
set AllowUsed = 1,
    PersonnelStatus = 0,
    ShopID = #{shopId},
    StockID = #{stockId}
where PersonnelName = #{personnelName}
  and Mobilephone = #{mobilePhone}

UPDATE Bas_Personnel
set PersonnelStatus = 2
where PersonnelName = #{personnelName}
  and Mobilephone = #{mobilePhone}

update Bas_Personnel
set ShopID     = #{newShopId},
    AllShopName = #{newDepartment},
    StockID    = #{stockId}
where (Mobilephone = #{mobileNo} or Telphone = #{mobileNo})
  and ShopID = #{shopId}
  and PersonnelName = #{staffName}

update Bas_Personnel
set Mobilephone = #{newPhone},
    Telphone    = #{newPhone}
where (Mobilephone = #{mobileNo} or Telphone = #{mobileNo})
  and PersonnelName = #{staffName}
